import type { TranslationKey } from '@/utils/i18n';

import { BaseModel, CastableTypes } from './base-model';
import { TeamPlan } from './team-plan';
import {
  AiCoachUsageStatus,
  aiCoachUsageStatusCanUse,
  BallUsageStatus,
  ballUsageStatusCanAnalyze,
  TeamPlanStatus,
  teamPlanStatusIsValid,
} from './team-status';
import { User } from './user';

export enum TeamType {
  SINGLE = 'single',
  MULTIPLE = 'multiple',
}

export class Team extends BaseModel {
  static _cast: Partial<Record<keyof Team, CastableTypes>> = {
    createdAt: 'date',
    updatedAt: 'date',
  };

  id!: string;
  imageUrl: string | null = null;
  presignedImageUrl: string | null = null;
  name: string | null = null;
  ownerUserId: string | null = null;
  teamType: TeamType | null = null;
  createdAt!: string;
  updatedAt!: string;
  deletionScheduledAt: string | null = null;

  teamPlan: TeamPlan | null;
  nextTeamPlan: TeamPlan | null;
  users: User[] = [];
  billingFailureReason: string | null = null;
  teamPlanCancelAt: string | null = null;
  teamPlanDowngradeAt: string | null = null;
  downgradePlanId: string | null = null;
  item: {
    aiCoachUsage: number;
    ballUsage: number;
    aiCoachAvailableCount: number;
    ballAvailableCount: number;
  } | null = null;

  constructor(data?: any) {
    super();
    this.init(Team, data);
    const teamPlan = TeamPlan.newInstance(TeamPlan, data?.teamPlan);
    this.teamPlan = teamPlan;
    const nextTeamPlan = TeamPlan.newInstance(TeamPlan, data?.nextTeamPlan);
    this.nextTeamPlan = nextTeamPlan;
    this.users = User.newInstances(User, data?.users);
    this.billingFailureReason = data?.billingFailureReason ?? null;
    this.item = data?.item;
  }

  /**
   * チームの動画解析の回数利用率。
   * 0以上を返却する。ないとは思うが、開発用でcurrent_usageなどを変更した場合、1以上が返却される場合もある。
   */
  get ballRate(): number {
    const usage = this.ballUsage;
    const maxUsage = this.maxBalls;

    if (maxUsage === 0) {
      return 0;
    }

    const rate = usage / maxUsage;
    return Math.max(0, rate);
  }

  /**
   * 残り利用可能日数。
   * 0以上を返却する。取得に失敗したときは0を返す。
   * nextTeamPlanが条件を満たしている場合はそちらも合算して返す。
   */
  get remainingDays() {
    if (!this.teamPlan?.isActive) {
      return 0;
    }
    // nextTeamPlanの有効化予約がされており (isPendingActivation: true)、
    // teamPlanとnextTeamPlanの間が空いていないときは、利用可能日数を通算とする
    const days =
      (+new Date(
        this.nextTeamPlan?.isPendingActivation &&
          this.nextTeamPlan.startDate === this.teamPlan.endDate
          ? this.nextTeamPlan.endDate
          : this.teamPlan.endDate,
      ) -
        +new Date()) /
      86400_000;
    return Math.max(0, days);
  }

  get teamPlanAvailability(): {
    isAvailable: boolean;
    unavailableReason: TranslationKey | null;
  } {
    const isExpired = this.remainingDays <= 0;
    if (isExpired) {
      return {
        isAvailable: false,
        unavailableReason: this.nextTeamPlan?.isPendingActivation
          ? 'next_team_plan_has_not_started_yet'
          : this.teamPlan
            ? 'team_plan_expired'
            : 'no_team_plan_found',
      };
    }
    return {
      isAvailable: true,
      unavailableReason: null,
    };
  }

  get ballAvailability(): {
    isAvailable: boolean;
    unavailableReason: TranslationKey | null;
  } {
    const totalUsage = this.currentTotalBallUsage;
    const totalAvailable = this.currentTotalBallAvailableCount;

    if (totalUsage === undefined || totalAvailable === undefined) {
      // TeamPlan も Item も枠を提供していないケース
      return {
        isAvailable: false,
        unavailableReason: this.teamPlanAvailability.unavailableReason ?? 'no_team_plan_found',
      };
    }

    if (totalAvailable === 0) {
      // 利用可能枠が 0 の場合
      // TeamPlan が有効なら使用量上限、期限切れなら期限切れ理由を返す
      return {
        isAvailable: false,
        unavailableReason: this.teamPlanAvailability.isAvailable
          ? 'you_have_reached_usage_limit'
          : this.teamPlanAvailability.unavailableReason!,
      };
    }

    if (totalUsage >= totalAvailable) {
      return {
        isAvailable: false,
        unavailableReason: 'you_have_reached_usage_limit',
      };
    }

    return {
      isAvailable: true,
      unavailableReason: null,
    };
  }

  /**
   * ボール解析の使用量（TeamPlan + Item の合算）
   * Flutter の ballUsage に対応
   */
  get ballUsage(): number {
    if (!this.teamPlan && !this.item) {
      return 0;
    }
    const planUsage = this.teamPlanAvailability.isAvailable
      ? this.teamPlan?.currentUsage ?? 0
      : 0;
    const itemUsage = this.item?.ballUsage ?? 0;
    return planUsage + itemUsage;
  }

  /**
   * ボール解析の上限数（TeamPlan + Item の合算）
   * Flutter の maxBalls に対応
   */
  get maxBalls(): number {
    if (!this.teamPlan && !this.item) {
      return 0;
    }
    const planMax = this.teamPlanAvailability.isAvailable
      ? this.teamPlan?.plan.maxBalls ?? 0
      : 0;
    const itemMax = this.item?.ballAvailableCount ?? 0;
    return planMax + itemMax;
  }

  /**
   * AI コーチの使用量（TeamPlan + Item の合算）
   * Flutter の aiCoachUsage に対応
   */
  get aiCoachUsage(): number {
    if (!this.teamPlan && !this.item) {
      return 0;
    }
    const planUsage = this.teamPlanAvailability.isAvailable
      ? this.teamPlan?.currentAiCoachUsage ?? 0
      : 0;
    const itemUsage = this.item?.aiCoachUsage ?? 0;
    return planUsage + itemUsage;
  }

  /**
   * AI コーチの上限数（TeamPlan + Item の合算）
   * Flutter の maxAICoachCount に対応
   */
  get maxAiCoachCount(): number {
    if (!this.teamPlan && !this.item) {
      return 0;
    }
    const planMax = this.teamPlanAvailability.isAvailable
      ? this.teamPlan?.plan.maxAiCoachs ?? 0
      : 0;
    const itemMax = this.item?.aiCoachAvailableCount ?? 0;
    return planMax + itemMax;
  }

  /**
   * プランの契約・有効期限状態
   * Flutter の teamPlanStatus に対応
   */
  get teamPlanStatus(): TeamPlanStatus {
    // 1. teamPlan が null または isActive != true の場合
    if (!this.teamPlan || this.teamPlan.isActive !== true) {
      return TeamPlanStatus.NO_CONTRACT;
    }

    // 2. 期限切れか
    const isExpired = this.remainingDays <= 0;
    if (isExpired) {
      if (this.nextTeamPlan?.isPendingActivation === true) {
        return TeamPlanStatus.NEXT_PLAN_PENDING;
      }
      return TeamPlanStatus.EXPIRED;
    }

    // 3. 期限警告（30日以内）
    if (this.remainingDays <= 30) {
      return TeamPlanStatus.EXPIRING_SOON;
    }

    // 4. 問題なし
    return TeamPlanStatus.OK;
  }

  /**
   * ボール解析の使用量状態
   * Flutter の ballAnalysisUsageStatus に対応
   */
  get ballUsageStatus(): BallUsageStatus {
    const usage = this.ballUsage;
    const maxUsage = this.maxBalls;

    // 上限到達
    if (usage >= maxUsage) {
      return BallUsageStatus.LIMIT_REACHED;
    }

    // 上限接近（90%以上）
    if (usage >= Math.floor(maxUsage * 0.9)) {
      return BallUsageStatus.LIMIT_APPROACHING;
    }

    // 正常
    return BallUsageStatus.OK;
  }

  /**
   * AI コーチの使用量状態
   * Flutter の aiCoachUsageStatus に対応
   */
  get aiCoachUsageStatus(): AiCoachUsageStatus {
    const usage = this.aiCoachUsage;
    const maxUsage = this.maxAiCoachCount;

    if (usage >= maxUsage) {
      return AiCoachUsageStatus.LIMIT_REACHED;
    }

    if (usage >= Math.floor(maxUsage * 0.9)) {
      return AiCoachUsageStatus.LIMIT_APPROACHING;
    }

    return AiCoachUsageStatus.OK;
  }

  /**
   * ボール解析が実行可能かどうか
   * Flutter の canAnalyzeBall に対応
   */
  get canAnalyzeBall(): boolean {
    return ballUsageStatusCanAnalyze(this.ballUsageStatus);
  }

  /**
   * AI コーチが利用可能かどうか
   * Flutter の canUseAiCoach に対応
   */
  get canUseAiCoach(): boolean {
    return aiCoachUsageStatusCanUse(this.aiCoachUsageStatus);
  }

  get currentTotalBallUsage() {
    if (this.teamPlan || this.item) {
      const isTeamPlanAvailable = this.teamPlanAvailability.isAvailable;
      return (isTeamPlanAvailable ? this.teamPlan?.currentUsage ?? 0 : 0) + (this.item?.ballUsage ?? 0);
    } else {
      return undefined;
    }
  }

  get currentTotalBallAvailableCount() {
    if (this.teamPlan || this.item) {
      const isTeamPlanAvailable = this.teamPlanAvailability.isAvailable;
      return (isTeamPlanAvailable ? this.teamPlan?.plan.maxBalls ?? 0 : 0) + (this.item?.ballAvailableCount ?? 0);
    } else {
      return undefined;
    }
  }

  get currentTotalAiCoachUsage() {
    if (this.teamPlan || this.item) {
      const isTeamPlanAvailable = this.teamPlanAvailability.isAvailable;
      return (isTeamPlanAvailable ? this.teamPlan?.currentAiCoachUsage ?? 0 : 0) + (this.item?.aiCoachUsage ?? 0);
    } else {
      return undefined;
    }
  }

  get currentTotalAiCoachAvailableCount() {
    if (this.teamPlan || this.item) {
      const isTeamPlanAvailable = this.teamPlanAvailability.isAvailable;
      return (isTeamPlanAvailable ? this.teamPlan?.plan.maxAiCoachs ?? 0 : 0) + (this.item?.aiCoachAvailableCount ?? 0);
    } else {
      return undefined;
    }
  }
}

