      ? this.teamPlan?.currentAiCoachUsage ?? 0
      : 0;
    const itemUsage = this.item?.aiCoachUsage ?? 0;
    return planUsage + itemUsage;
  }

  /**
   * AI コーチの上限数（TeamPlan + Item の合算）
   * Flutter の maxAICoachCount に対応
   */
  get maxAiCoachCount(): number {
    if (!this.teamPlan && !this.item) {
      return 0;
    }
    const planMax = this.teamPlanAvailability.isAvailable
      ? this.teamPlan?.plan.maxAiCoachs ?? 0
      : 0;
    const itemMax = this.item?.aiCoachAvailableCount ?? 0;
    return planMax + itemMax;
  }

  /**
   * プランの契約・有効期限状態
   * Flutter の teamPlanStatus に対応
   */
  get teamPlanStatus(): TeamPlanStatus {
    // 1. teamPlan が null または isActive != true の場合
    if (!this.teamPlan || this.teamPlan.isActive !== true) {
      return TeamPlanStatus.NO_CONTRACT;
    }

    // 2. 期限切れか
    const isExpired = this.remainingDays <= 0;
    if (isExpired) {
      if (this.nextTeamPlan?.isPendingActivation === true) {
