import _ from 'lodash';
import moment from 'moment';

import { Team, TeamType } from '@/models/team';
import { TeamPlan } from '@/models/team-plan';

import { translate } from './i18n';

export class StringUtil {
  private static calculateMatchRatio(query: string, target: string): number {
    let matchCount = 0;
    const queryCharCount: { [key: string]: number } = {};
    const targetCharCount: { [key: string]: number } = {};

    // クエリの各文字の出現回数をカウント
    for (const char of query) {
      queryCharCount[char] = (queryCharCount[char] || 0) + 1;
    }

    // ターゲットの各文字の出現回数をカウント
    for (const char of target) {
      targetCharCount[char] = (targetCharCount[char] || 0) + 1;
    }

    // クエリの各文字に対して、ターゲットに含まれる分だけマッチさせる
    for (const char in queryCharCount) {
      if (targetCharCount[char]) {
        matchCount += Math.min(queryCharCount[char], targetCharCount[char]);
      }
    }

    return matchCount / query.length;
  }

  private static cleanString(str: string): string {
    // 空白等のジャンク文字を除去
    return str.replace(/\s+/g, '').toLowerCase();
  }
  /**
   * @deprecated
   */

  static getSimilarStr(
    str: string,
    names: string[],
    threshold = 0.5,
  ): string[] {
    const cleanedQuery = this.cleanString(str);

    const s = names
      .map((name) => {
        const cleanedName = this.cleanString(name);
        const matchRatio = this.calculateMatchRatio(cleanedQuery, cleanedName);
        return { name, matchRatio };
      })
      .filter((result) => result.matchRatio >= threshold);

    return _.map(s, (s) => s.name);
  }

  /**
   * Checks if the uuid is valid (not strict)
   */
  static isValidUUID(str: string) {
    return !!str.match(/[0-9A-Fa-f]{8}-([0-9A-Fa-f]{4}-){3}[0-9A-Fa-f]{12}$/);
  }

  static getTeamItemBallUsageString = (team: Team) => {
    const current = team.currentTotalBallUsage;
    const max = team.currentTotalBallAvailableCount;
    // 0 is falsy.
    return current !== undefined && max !== undefined
      ? `${current!.toLocaleString()}/${max!.toLocaleString()}`
      : '-';
  };

  static getTeamItemAiCoachUsageString = (team: Team) => {
    const current = team.currentTotalAiCoachUsage;
    const max = team.currentTotalAiCoachAvailableCount;
    return current !== undefined && max !== undefined
      ? `${current!.toLocaleString()}/${max!.toLocaleString()}`
      : '-';
  };

  static getTeamPlanItemBallUsageString = (teamPlan: TeamPlan) => {
    const current = teamPlan.currentUsage;
    const max = teamPlan.plan.maxBalls;
    return current !== undefined && max !== undefined
      ? `${current!.toLocaleString()}/${max!.toLocaleString()}`
      : '-';
  };

  static getTeamPlanItemAiCoachUsageString = (teamPlan: TeamPlan) => {
    const current = teamPlan.currentAiCoachUsage;
    const max = teamPlan.plan.maxAiCoachs;
    return current !== undefined && max !== undefined
      ? `${current!.toLocaleString()}/${max!.toLocaleString()}`
      : '-';
  };

  static getPeriodDispString = (
    date: Date | null,
    format: string = 'YYYY-MM-DD H:mm',
  ) => {
    return date ? moment(date).format(format) : '-';
  };

  static getTeamTypeString = (teamType: TeamType | null) => {
    if (!teamType) {
      return '-';
    }
    return translate(
      teamType === TeamType.SINGLE ? 'team_type_single' : 'team_type_multiple',
    );
  };
}

