import { Resource } from '@/models/resource';
import { Session } from '@/models/session';
import { Team } from '@/models/team';
import { BallUsageStatus, TeamPlanStatus } from '@/models/team-status';
import { User } from '@/models/user';
import { translate, TranslationKey } from '@/utils/i18n';

type Availability = { isAvailable: boolean; unavailableReason: string | null };

export const checkAnalysisAvailability = (
  session: Session,
  user: User,
  team: Team,
): Availability => {
  if (!user.hasBasicWriteAccessFor(session)) {
    return {
      isAvailable: false,
      unavailableReason: translate(
        'insufficient_permission_for_analyzing_video',
      ),
    };
  }
  // ボール使用量チェック（TeamPlan + Item を合算）
  if (!team.canAnalyzeBall) {
    let reasonKey: TranslationKey;
    if (team.ballUsageStatus === BallUsageStatus.LIMIT_REACHED) {
      reasonKey = 'you_have_reached_usage_limit';
    } else if (team.teamPlanStatus === TeamPlanStatus.EXPIRED) {
      reasonKey = 'team_plan_expired';
    } else if (team.teamPlanStatus === TeamPlanStatus.NO_CONTRACT) {
      reasonKey = 'no_team_plan_found';
    } else if (team.teamPlanStatus === TeamPlanStatus.NEXT_PLAN_PENDING) {
      reasonKey = 'next_team_plan_has_not_started_yet';
    } else {
      reasonKey = 'you_have_reached_usage_limit';
    }
    return {
      isAvailable: false,
      unavailableReason: translate(reasonKey),
    };
  }
  return {
    isAvailable: true,
    unavailableReason: null,
  };
};

export const checkReanalysisAvailability = (
  resource: Resource,
  user: User,
  team: Team,
): Availability => {
  if (!resource.canReanalyze) {
