@web/src/utils/analysis.util.ts 
Flutter 側のコードでは以下のように警告の表示制御を行っている。 teamType によって条件が異なる

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/components/custom_alert_snack_bar.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class UsageLimitAlertSnackBar extends ConsumerWidget {
  const UsageLimitAlertSnackBar({
    super.key,
  });

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamListState = ref.watch(teamListControllerProvider);
    final teamId = ref.watch(profileStorageProvider).getTeamId();

    return teamListState.fold(
      data: (teams) {
        final team = teams.where((team) => team.id == teamId!).firstOrNull;
        final isSingleTeam = team?.isSingleUserTeam == true;
        final text = _getText(
          context,
          team?.teamPlanStatus,
          team?.ballAnalysisUsageStatus,
          isSingleTeam,
        );
        final colors = _getColor(team);

        if (text == null) return const SizedBox.shrink();

        return CustomAlertSnackBar(
          foregroundColor: colors.foregroundColor,
          backgroundColor: colors.backgroundColor,
          child: Text(text, style: TextStyle(color: colors.foregroundColor)),
        );
      },
      error: (error) => CustomAlertSnackBar(
        foregroundColor: Colors.white,
        backgroundColor: ColorManager.error,
        child: Text(
          context.l10n.usage_limit_alert_snack_bar__could_not_get,
        ),
      ),
      loading: () => const SizedBox.shrink(),
    );
  }

  ({
    Color foregroundColor,
    Color backgroundColor,
  }) _getColor(Team? team) {
    // エラーレベル（期限切れ、上限到達など）
    if (team?.canAnalyzeBall != true) {
      return (
        foregroundColor: Colors.white,
        backgroundColor: ColorManager.error,
      );
    }
    // 警告レベル（接近中）
    return (
      foregroundColor: ColorManager.primaryText,
      backgroundColor: ColorManager.warning,
    );
  }

  String? _getText(
    BuildContext context,
    TeamPlanStatus? planStatus,
    BallAnalysisUsageStatus? usageStatus,
    bool isSingleTeam,
  ) {
    if (isSingleTeam) {
      // シングルユーザーチームではサブスクが自動更新されるため usageStatus だけで判定
      return switch (usageStatus) {
        BallAnalysisUsageStatus.limitReached =>
          context.l10n.usage_limit_alert_snack_bar__reached_limit,
        BallAnalysisUsageStatus.limitApproaching =>
          context.l10n.usage_limit_alert_snack_bar__limit_is_approaching,
        BallAnalysisUsageStatus.ok || null => null
      };
    } else {
      // マルチユーザーチームでは最初に planStatus に基づく警告を表示し、
      // プランが正常なら usageStatus に基づく判定をする
      switch (planStatus) {
        case TeamPlanStatus.noContract:
          return context.l10n.usage_limit_alert_snack_bar__no_contract;
        case TeamPlanStatus.nextPlanPending:
          return context.l10n.usage_limit_alert_snack_bar__next_plan_pending;
        case TeamPlanStatus.expired:
          return context.l10n.usage_limit_alert_snack_bar__expired;
        case TeamPlanStatus.expiringSoon:
          return context.l10n.usage_limit_alert_snack_bar__expiring_soon;
        case null:
          return context.l10n.usage_limit_alert_snack_bar__failed_to_load;
        case TeamPlanStatus.ok:
          if (usageStatus == BallAnalysisUsageStatus.limitReached) {
            return context.l10n.usage_limit_alert_snack_bar__reached_limit;
          } else if (usageStatus == BallAnalysisUsageStatus.limitApproaching) {
            return context
                .l10n.usage_limit_alert_snack_bar__limit_is_approaching;
          } else {
            return null;
          }
      }
    }
  }
}

